mapper.select:
select al.id,
       al.task_id,
       al.action_type,
       al.create_by,
       al.create_time,
       al.other_info_01,
       al.other_info_02,
       al.other_info_03,
       al.other_info_04,
       al.other_info_05,
       al.other_info_06,
       al.other_info_07,
       su.user_name
from action_log as al
         left join sys_user as su on su.user_id = al.create_by


        and al.id = #{id}


        and al.task_id = #{taskId}


        and al.action_type = #{actionType}


        and al.create_by = #{createBy}


        and al.create_time = #{createTime}


        and al.other_info_01 = #{otherInfo01}


        and al.other_info_02 = #{otherInfo02}


        and al.other_info_03 = #{otherInfo03}


        and al.other_info_04 = #{otherInfo04}


        and al.other_info_05 = #{otherInfo05}


        and al.other_info_06 = #{otherInfo06}


        and al.other_info_07 = #{otherInfo07}
